#!/bin/bash
# =============================================================================
# Vector PoC — COMPLETE EC2 Deploy + Run Script
# =============================================================================
# Paste this ENTIRE script into EC2 Instance Connect or Session Manager.
# It embeds the full test suite, downloads the dataset, and runs everything.
# =============================================================================
set -e

echo "=========================================="
echo "Vector PoC — Full Deploy"
echo "=========================================="

# -- Install deps --
echo "[1/5] Installing dependencies..."
sudo yum install -y python3 python3-pip 2>/dev/null || sudo dnf install -y python3 python3-pip 2>/dev/null || true
python3 -m pip install --quiet psycopg[binary] numpy rich click python-dotenv pyarrow vectordb-bench 2>/dev/null || \
pip3 install --quiet psycopg[binary] numpy rich click python-dotenv pyarrow vectordb-bench

# -- Extract embedded test suite --
echo "[2/5] Extracting test suite..."
cd ~
base64 -d << 'B64EOF' | tar xzf -

B64EOF

# -- Write .env --
echo "[3/5] Configuring connection..."
cat > ~/vector_poc_tests/.env << 'ENVEOF'
CRDB_HOST=your-cluster.aws-us-west-2.cockroachlabs.cloud
CRDB_PORT=26257
CRDB_USER=your_username
CRDB_PASSWORD=your_password
CRDB_DATABASE=vectortest
CRDB_SSLMODE=verify-full
CRDB_SSLROOTCERT=/home/ec2-user/your-cluster-ca.crt
VECTOR_DIM=1536
DATASET_SIZES=50000,100000,250000,500000
QUERY_COUNT=1000
TOP_K=10
ITERATIONS=3
BATCH_SIZE=500
CONCURRENCY_LEVELS=1,5,10
FRESHNESS_TRIALS=100
VECTOR_SEARCH_BEAM_SIZE=32
ENVEOF

# -- Download VectorDBBench dataset --
echo "[4/5] Downloading VectorDBBench 1536D/500K dataset (~4.5 GB, ~3-5 min)..."
python3 << 'PYEOF'
from vectordb_bench.backend.cases import CaseType
import os

case_cls = CaseType.Performance1536D500K.case_cls()
ds = case_cls.dataset
print("  Downloading from S3...")
ds.prepare()

src_dir = "/tmp/vectordb_bench/dataset/openai/openai_medium_500k"
dst_dir = os.path.expanduser("~/vector_poc_tests/data/vectordbbench_1536d_500k")
os.makedirs(dst_dir, exist_ok=True)
for src_name, dst_name in [
    ("shuffle_train.parquet", "train.parquet"),
    ("test.parquet", "test.parquet"),
    ("neighbors.parquet", "neighbors.parquet"),
]:
    src = os.path.join(src_dir, src_name)
    dst = os.path.join(dst_dir, dst_name)
    if os.path.exists(src) and not os.path.exists(dst):
        os.symlink(src, dst)
print("  Dataset ready!")
PYEOF

# -- Run tests --
echo "[5/5] Running test suite..."
cd ~/vector_poc_tests
python3 run.py --suite all 2>&1 | tee ~/vector_poc_results.log

echo ""
echo "=========================================="
echo "DONE! Results saved to:"
echo "  ~/vector_poc_results.log"
echo "  ~/vector_poc_tests/reports/"
echo "=========================================="
